std::string recv_line(int sockfd) {
    std::string line;
    char buf;
    while (true) {
        ssize_t n = recv(sockfd, &buf, 1, 0);
        if (n <= 0) break;
        line += buf;
        if (line.size() >= 2 && line.compare(line.size() - 2, 2, "\r\n") == 0) {
            line.erase(line.size() - 2);
            break;
        }
    }
    return line;
}

void send_cmd(int sockfd, const std::string& cmd) {
    std::string full_cmd = cmd + "\r\n";
    send(sockfd, full_cmd.c_str(), full_cmd.size(), 0);
}

int get_response(int sockfd, std::string& resp) {
    resp = recv_line(sockfd);
    if (resp.size() < 4) {
        throw std::runtime_error("Invalid FTP response");
    }
    try {
        return std::stoi(resp.substr(0, 3));
    } catch (...) {
        throw std::runtime_error("Invalid FTP response code");
    }
}

int send_and_recv(int sockfd, const std::string& cmd, std::string& resp) {
    send_cmd(sockfd, cmd);
    return get_response(sockfd, resp);
}

int connect_to_host(const std::string& hostname, int port) {
    struct addrinfo hints{}, *res;
    hints.ai_family = AF_UNSPEC;
    hints.ai_socktype = SOCK_STREAM;

    if (getaddrinfo(hostname.c_str(), std::to_string(port).c_str(), &hints, &res) != 0) {
        throw std::runtime_error("Failed to resolve hostname");
    }

    int sockfd = socket(res->ai_family, res->ai_socktype, res->ai_protocol);
    if (sockfd < 0) {
        freeaddrinfo(res);
        throw std::runtime_error("Failed to create socket");
    }

    if (connect(sockfd, res->ai_addr, res->ai_addrlen) < 0) {
        freeaddrinfo(res);
        close(sockfd);
        throw std::runtime_error("Failed to connect to host");
    }

    freeaddrinfo(res);
    return sockfd;
}

