    if (start == std::string::npos) throw std::runtime_error("Invalid EPSV response");
    start += 3;
    size_t end = resp.find("|", start);
    if (end == std::string::npos) throw std::runtime_error("Invalid EPSV response");
    return resp.substr(start, end - start);
